const request = $input.first().json.request;
const metadata = $input.first().json.metadata;

// Construir el prompt para el agente IA
const systemPrompt = `Eres un asistente AI experto en desarrollo web React + TypeScript para el sitio web NeuroInnova (https://neuroinnova.com.py).

Tu trabajo es analizar solicitudes de cambio y generar las modificaciones necesarias de código.

REGLAS IMPORTANTES:
1. SIEMPRE genera cambios COMPLETOS y funcionales
2. Si es una nueva página/sección, incluye TODOS los archivos necesarios
3. Actualiza SIEMPRE las rutas en App.tsx y la navegación en Header.tsx
4. Usa los componentes de shadcn/ui existentes
5. Mantén la consistencia con el diseño actual
6. Para archivos nuevos, usa oldCode: "" y lineStart/lineEnd: 0

ESTRUCTURA DEL PROYECTO:
- Páginas: src/pages/
- Componentes: src/components/
- Servicios: src/services/
- Colores: Primario #2C5F8B, Secundario #7CB342
- UI Framework: shadcn/ui + Tailwind CSS`;

const userPrompt = `SOLICITUD DE CAMBIO:
Descripción: "${request.description}"
Tipo: ${request.type}
Sección: ${request.section}
Prioridad: ${request.priority}

Genera los cambios necesarios en formato JSON:
{
  "files": ["lista de archivos a modificar"],
  "changes": [
    {
      "file": "ruta/archivo.tsx",
      "oldCode": "código actual (vacío si es nuevo)",
      "newCode": "código nuevo completo",
      "lineStart": número,
      "lineEnd": número
    }
  ],
  "commitMessage": "mensaje descriptivo",
  "requiresReview": boolean,
  "diagnostics": {
    "filesChecked": ["archivos verificados"],
    "issuesFound": ["problemas encontrados"],
    "recommendations": ["recomendaciones"]
  }
}`;

return [{
  json: {
    systemPrompt,
    userPrompt,
    originalRequest: request,
    metadata,
    temperature: 0.2,
    maxTokens: 32768
  }
}];

const question = $input.first().json.question;
const conversationId = $input.first().json.conversationId || null;
const metadata = $input.first().json.metadata;

const systemPrompt = `Eres un asistente IA amigable y conversacional para el sitio web de NeuroInnova.

Tu rol es responder preguntas sobre el contenido actual del sitio web de manera precisa y detallada.

INFORMACIÓN DEL SITIO:
