4. NO sugieras cambios, solo informa sobre el estado actual`;

const userPrompt = `Pregunta del usuario: "${question}"

Por favor, responde de manera completa y conversacional.`;

return [{
  json: {
    systemPrompt,
    userPrompt,
    conversationId,
    metadata,
    temperature: 0.7,
    maxTokens: 4096
  }
}];

const aiResponse = $input.first().json;
const isChangeRequest = $('format_change_request').first()?.json ? true : false;

if (isChangeRequest) {
  // Procesar respuesta de cambio
  let processedChange;

  try {
    // La respuesta puede venir en diferentes formatos
    if (typeof aiResponse.response === 'string') {
      // Intentar extraer JSON de la respuesta
      const jsonMatch = aiResponse.response.match(/```json\n?([\s\S]*?)\n?```/);
      if (jsonMatch) {
        processedChange = JSON.parse(jsonMatch[1]);
      } else {
        processedChange = JSON.parse(aiResponse.response);
      }
    } else if (aiResponse.message?.content) {
      const jsonMatch = aiResponse.message.content.match(/```json\n?([\s\S]*?)\n?```/);
      if (jsonMatch) {
        processedChange = JSON.parse(jsonMatch[1]);
      } else {
        processedChange = JSON.parse(aiResponse.message.content);
      }
    } else {
      processedChange = aiResponse;
    }
  } catch (error) {
    return [{
      json: {
        success: false,
        error: 'No se pudo procesar la respuesta del AI: ' + error.message,
        rawResponse: aiResponse
      }
    }];
  }

  // Validar estructura
  if (!processedChange.files || !processedChange.changes) {
    return [{
      json: {
        success: false,
        error: 'La respuesta del AI no tiene el formato esperado',
        rawResponse: aiResponse
      }
    }];
  }

  return [{
    json: {
      success: true,
      processedChange: processedChange,
      requiresGitHub: true,
      originalRequest: $('format_change_request').first().json.originalRequest
    }
  }];

} else {
  // Procesar respuesta conversacional
  let message;

  if (typeof aiResponse === 'string') {
    message = aiResponse;
  } else if (aiResponse.response) {
    message = aiResponse.response;
  } else if (aiResponse.message?.content) {
    message = aiResponse.message.content;
  } else if (aiResponse.choices?.[0]?.message?.content) {
    message = aiResponse.choices[0].message.content;
  } else {
    message = JSON.stringify(aiResponse);
  }

  return [{
    json: {
      success: true,
      message: message,
      conversationId: $('format_question').first().json.conversationId,
      requiresGitHub: false
    }
  }];
}

