// Combinar las respuestas de diferentes ramas
const input = $input.all();

// Buscar la entrada correcta
let response;
for (const item of input) {
  if (item.json) {
    response = item.json;
    break;
  }
}

if (!response) {
  return [{
    json: {
      success: false,
      error: 'No se recibió respuesta válida'
    }
  }];
}

// Si fue un cambio aplicado a GitHub
if (response.githubResult) {
  return [{
    json: {
      success: true,
      processedChange: response.processedChange,
      message: 'Cambios aplicados exitosamente. El sitio se actualizará en 2-3 minutos.',
      commitSha: response.githubResult.sha
    }
  }];
}

// Si fue una pregunta conversacional
if (response.message && !response.requiresGitHub) {
  return [{
    json: {
      success: true,
      message: response.message,
      conversationId: response.conversationId
    }
  }];
}

// Si hubo un error
if (!response.success) {
  return [{
    json: {
      success: false,
      error: response.error || 'Error desconocido',
      details: response
    }
  }];
}

// Respuesta por defecto
return [{
  json: response
}];

// Nodo de manejo de errores
const error = $input.first().error;
const context = $input.first().json || {};

return [{
  json: {
    success: false,
    error: error?.message || 'Error desconocido en el workflow',
    errorDetails: {
      message: error?.message,
      stack: error?.stack,
      context: context
    },
    timestamp: new Date().toISOString()
  }
}];
